import { Link } from "react-router-dom";
import { MapPin } from "lucide-react";
import { Badge } from "@/components/ui/badge";

interface NearbyCitiesSectionProps {
  currentService: string;
  currentCity: string;
  serviceName: string;
}

const NearbyCitiesSection = ({ 
  currentService, 
  currentCity, 
  serviceName 
}: NearbyCitiesSectionProps) => {
  const cityGroups: { [key: string]: string[] } = {
    "york": ["north-york", "markham", "vaughan", "aurora", "newmarket", "king"],
    "north-york": ["york", "markham", "vaughan", "aurora", "newmarket"],
    "markham": ["york", "north-york", "vaughan", "stouffville", "aurora"],
    "vaughan": ["york", "north-york", "markham", "caledon", "king"],
    "aurora": ["newmarket", "york", "markham", "king", "east-gwillimbury"],
    "newmarket": ["aurora", "east-gwillimbury", "york", "king", "georgina"],
    "king": ["king-city", "vaughan", "aurora", "newmarket", "caledon"],
    "king-city": ["king", "vaughan", "aurora", "caledon"],
    "stouffville": ["markham", "york", "aurora", "east-gwillimbury"],
    "east-gwillimbury": ["newmarket", "aurora", "georgina", "stouffville"],
    "georgina": ["newmarket", "east-gwillimbury", "orillia"],
    "caledon": ["vaughan", "king", "king-city"],
    "orillia": ["georgina", "newmarket", "east-gwillimbury"]
  };

  const cityNames: { [key: string]: string } = {
    "york": "York",
    "north-york": "North York",
    "markham": "Markham",
    "king": "King",
    "king-city": "King City",
    "stouffville": "Stouffville",
    "aurora": "Aurora",
    "newmarket": "Newmarket",
    "east-gwillimbury": "East Gwillimbury",
    "georgina": "Georgina",
    "vaughan": "Vaughan",
    "caledon": "Caledon",
    "orillia": "Orillia"
  };

  const nearbyCities = cityGroups[currentCity] || [];
  const displayCities = nearbyCities.slice(0, 6);

  if (displayCities.length === 0) return null;

  return (
    <section className="py-12 bg-background">
      <div className="container">
        <div className="flex items-center gap-3 mb-6">
          <MapPin className="w-6 h-6 text-primary" />
          <h2 className="text-2xl md:text-3xl font-bold text-primary-dark">
            We Also Serve Nearby Areas
          </h2>
        </div>
        <p className="text-muted-foreground mb-6">
          Looking for {serviceName.toLowerCase()} in nearby communities? We proudly serve:
        </p>
        
        <div className="flex flex-wrap gap-3">
          {displayCities.map((city) => (
            <Link 
              key={city}
              to={`/${currentService}/${city}`}
            >
              <Badge 
                variant="outline" 
                className="text-base px-4 py-2 cursor-pointer"
              >
                {serviceName} in {cityNames[city]}
              </Badge>
            </Link>
          ))}
        </div>

        <p className="text-sm text-muted-foreground mt-6">
          Fast response times across York Region and the Greater Toronto Area. 
          <Link to="/service-areas" className="text-primary font-semibold ml-1 underline">
            View all service areas
          </Link>
        </p>
      </div>
    </section>
  );
};

export default NearbyCitiesSection;
